import React, { useState } from "react";
import axios from "axios";
import "./App.css";

function App() {

  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);

  const sendMessage = async () => {

    if (!input.trim()) return;

    const userMsg = {
      role: "user",
      text: input
    };

    setMessages(prev => [...prev, userMsg]);
    setInput("");
    setLoading(true);

    try {

      /* ✅ DIRECT BACKEND CALL */
      const res = await axios.post(
        "http://localhost:5000/api/chat",
        { message: input }
      );

      const aiMsg = {
        role: "ai",
        text: res.data.reply
      };

      setMessages(prev => [...prev, aiMsg]);

    } catch (err) {

      console.log("FRONTEND ERROR:", err);

      setMessages(prev => [
        ...prev,
        { role: "ai", text: "AI Error" }
      ]);
    }

    setLoading(false);
  };

  return (

    <div className="app">

      {/* SIDEBAR */}
      <div className="sidebar">
        <h2 className="logo">🤖 AI Chatbot</h2>

        <h4>Conversations</h4>
        <p>{messages.length} messages</p>

        <button onClick={() => setMessages([])}>
          Clear Chat
        </button>
      </div>

      {/* CHAT AREA */}
      <div className="chat-area">

        <div className="chat-header">
          🤖 AI Chatbot
        </div>

        <div className="memory-tabs">
          <span className="tab active">Semantic</span>
          <span className="tab">Episodic</span>
          <span className="tab">Procedural</span>
          <span className="tab">Emotional</span>
        </div>

        <div className="messages">

          {messages.map((msg, i) => (
            <div
              key={i}
              className={msg.role === "user" ? "user-msg" : "ai-msg"}
            >
              {msg.text}
            </div>
          ))}

          {loading && <div className="ai-msg">AI thinking...</div>}

        </div>

        <div className="input-bar">

          <input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Message AI Chatbot..."
            onKeyDown={(e) => {
              if (e.key === "Enter") sendMessage();
            }}
          />

          <button onClick={sendMessage}>
            Send
          </button>

        </div>

      </div>

      {/* RIGHT PANEL */}
      <div className="memory-panel">

        <h3>SEMANTIC MEMORY</h3>
        <div className="card">
          <p>Topics auto learned</p>
        </div>

        <h3>USER PROFILE</h3>
        <div className="card">
          <p>Name & facts remembered</p>
        </div>

        <h3>EMOTIONAL</h3>
        <div className="card">
          <p>Preferences tracked</p>
        </div>

      </div>

    </div>
  );
}

export default App;
